  function formatSuccessChargeText(total, currency = "") {
    const symbolMap = {
      USD: "$",
      JOD: "د.أ",
      SAR: "ر.س",
      EGP: "ج.م"
    };
    const amount = Number(total);
    const rawCurrency = String(currency || "").trim();
    const currencyKey = rawCurrency.toUpperCase();
    const currencyText = symbolMap[currencyKey] || rawCurrency;
    if (Number.isFinite(amount)) {
      const suffix = currencyText ? String(currencyText).trim() : "";
      return `${amount.toFixed(3)}${suffix}`.trim();
    }
    const rawAmount = String(total == null ? "" : total).trim();
    if (rawAmount) return rawAmount.slice(0, 14);
    return currencyText || "$";
  }

