  try { window.showWalletActivityOverlay = showWalletActivityOverlay; } catch (_) {}

  function hasWalletCreditMotionSession(user) {
    try {
      const info = typeof readSessionInfo === "function" ? (readSessionInfo() || {}) : {};
      const userUid = user && user.uid ? String(user.uid).trim() : "";
      const infoUid = String(info.uid || "").trim();
      const sessionKey = String(info.sessionKey || (typeof getLocalSessionKey === "function" ? getLocalSessionKey() : "") || "").trim();
      if (!sessionKey) return false;
      if (userUid && infoUid && userUid !== infoUid) return false;
      if (typeof isSessionExpiredLocal === "function" && isSessionExpiredLocal(info)) return false;
      return true;
    } catch (_) {
      return false;
    }
  }

  function isWalletCreditMotionBlocked(user) {
    if (!user || !user.uid) return true;
    if (!hasWalletCreditMotionSession(user)) return true;
    try {
      const hash = String(location.hash || "").toLowerCase();
      if (/^#\/login(?:\/|$)?/.test(hash)) return true;
    } catch (_) {}
    try {
      if (document.body && document.body.classList.contains("login-route-active")) return true;
      if (document.body && String(document.body.getAttribute("data-inline-route") || "").toLowerCase() === "login") return true;
    } catch (_) {}
    try {
      const loginInline = document.getElementById("loginInline");
      if (loginInline && !loginInline.classList.contains("hidden")) return true;
    } catch (_) {}
    return false;
  }

  function parseWalletMotionNumber(value) {
    const n = Number(value);
    return Number.isFinite(n) ? n : null;
  }

  function parseWalletMotionTimestamp(entry) {
    const raw =
      entry?.createdAt ??
      entry?.created_at ??
      entry?.timestamp ??
      entry?.computedAt ??
      null;
    if (!raw) return 0;
    if (raw instanceof Date) return raw.getTime();
    if (raw && typeof raw.toDate === "function") {
      try {
        const date = raw.toDate();
        return date instanceof Date ? date.getTime() : 0;
      } catch (_) {
        return 0;
      }
    }
    if (typeof raw === "string") {
      const ms = Date.parse(raw);
      return Number.isFinite(ms) ? ms : 0;
    }
    if (raw && typeof raw.seconds === "number") {
      return raw.seconds * 1000;
    }
    return 0;
  }

  function collectWalletMotionEntries(data) {
    const out = [];
    let map = null;
    if (data && data.entriesMap && typeof data.entriesMap === "object" && !Array.isArray(data.entriesMap)) {
      map = data.entriesMap;
    } else if (data && data.entries_map && typeof data.entries_map === "object" && !Array.isArray(data.entries_map)) {
      map = data.entries_map;
    } else if (data && data.entriesById && typeof data.entriesById === "object" && !Array.isArray(data.entriesById)) {
      map = data.entriesById;
    } else if (data && data.entriesMap && data.entriesMap.mapValue && data.entriesMap.mapValue.fields) {
      map = {};
      Object.entries(data.entriesMap.mapValue.fields || {}).forEach(([entryKey, entryValue]) => {
        map[entryKey] = (entryValue && entryValue.mapValue && entryValue.mapValue.fields) || entryValue || {};
      });
    }
    Object.entries(map || {}).forEach(([entryKey, entry]) => {
      if (!entry || typeof entry !== "object") return;
      out.push({ ...entry, __entryKey: String(entry.entryKey || entryKey || "").trim() || String(entryKey || "").trim() });
    });
    out.sort((a, b) => parseWalletMotionTimestamp(a) - parseWalletMotionTimestamp(b));
    return out;
  }

  function resolveWalletMotionPeer(entry) {
    const keys = [
      "transferPeer", "transferPeerUid",
      "peerWebuid", "receiverWebuid", "recipientWebuid", "targetWebuid",
      "peerUid", "receiverUid", "recipientUid", "targetUid"
    ];
    for (const key of keys) {
      const value = String(entry?.[key] || "").trim();
      if (!value) continue;
      if (value === "-" || value === "أ¢â‚¬â€‌" || value === "مستخدم" || value === "مرسل" || value === "مستلم") continue;
      return value;
    }
    return "";
  }

  function isWalletMotionAdminText(value) {
    const text = String(value || "").trim();
    if (!text) return false;
    return /إدارة|الادارة|زيادة\s*رصيد|لوحة\s*الإدارة|لوحة\s*الادارة|تعيين\s*رصيد/.test(text);
  }

  function classifyWalletMotionEntry(entry) {
    const kind = String(entry?.kind || entry?.__kind || "deposit").trim().toLowerCase();
    if (kind === "withdraw") return null;

    const amount =
      parseWalletMotionNumber(entry?.added) ??
      parseWalletMotionNumber(entry?.addedAmount) ??
      parseWalletMotionNumber(entry?.addedUSD) ??
      parseWalletMotionNumber(entry?.amountUSD) ??
      parseWalletMotionNumber(entry?.amount);
    if (!(Number.isFinite(amount) && amount > 0)) return null;

    const currency = String(entry?.currency || entry?.addedCurrency || "USD").trim().toUpperCase() || "USD";
    const methodName = String(entry?.methodName || entry?.method || "").trim();
    const description = String(entry?.description || "").trim();
    const peer = resolveWalletMotionPeer(entry);
    const combined = [methodName, description].join(" ").trim();

    if (/استرداد|إرجاع\s*بعد|ارجاع\s*بعد|عكس\s*إيداع|عكس\s*ايداع/.test(combined)) {
      return null;
    }

    if (peer || /تحويل\s*من/.test(methodName)) {
      return {
        title: "تم استلام حوالة",
        bannerText: "تم استلام حوالة",
        message: "تمت إضافة الحوالة إلى رصيدك بنجاح.",
        note: "يمكنك مراجعة الحركة من سجل المحفظة.",
        detailLabel: "المرسل",
        detailText: peer || "مستخدم",
        amount,
        currency
      };
    }

    if (isWalletMotionAdminText(combined)) {
      return {
        title: "تمت زيادة الرصيد",
        bannerText: "تمت زيادة الرصيد",
        message: "تمت إضافة المبلغ إلى رصيدك بنجاح.",
        note: "يمكنك مراجعة الحركة من سجل المحفظة.",
        detailLabel: "المصدر",
        detailText: "زيادة رصيد من ادارة الموقع",
        amount,
        currency
      };
    }

    if (/طلب\s*إيداع|قبول\s*طلب\s*إيداع|قبول\s*ايداع|إيداع|ايداع/.test(combined)) {
      return {
        title: "تم قبول الإيداع",
        bannerText: "تم قبول الإيداع",
        message: "تمت إضافة المبلغ إلى رصيدك بنجاح.",
        note: "يمكنك مراجعة الحركة من سجل المحفظة.",
        detailLabel: "نوع العملية",
        detailText: "إيداع مقبول",
        amount,
        currency
      };
    }

    return null;
  }

  function resetWalletCreditMotionWatcher() {
    if (walletCreditMotionWatcherState.unsubscribe) {
      try { walletCreditMotionWatcherState.unsubscribe(); } catch (_) {}
    }
    if (walletCreditMotionWatcherState.pollTimer) {
      try { clearInterval(walletCreditMotionWatcherState.pollTimer); } catch (_) {}
    }
    walletCreditMotionWatcherState.unsubscribe = null;
    walletCreditMotionWatcherState.pollTimer = null;
    walletCreditMotionWatcherState.uid = "";
    walletCreditMotionWatcherState.primed = false;
    walletCreditMotionWatcherState.seenKeys = new Set();
  }

  function walletCreditMotionSeenStorageKey(uid) {
    const safeUid = String(uid || "").trim();
    return safeUid ? (WALLET_CREDIT_MOTION_SEEN_PREFIX + safeUid) : "";
  }

  function readWalletCreditMotionSeenKeys(uid) {
    const key = walletCreditMotionSeenStorageKey(uid);
    if (!key) return new Set();
    try {
      const raw = localStorage.getItem(key);
      const parsed = JSON.parse(raw || "[]");
      if (!Array.isArray(parsed)) return new Set();
      return new Set(
        parsed
          .map((entry) => String(entry || "").trim())
          .filter(Boolean)
          .slice(-WALLET_CREDIT_MOTION_MAX_SEEN)
      );
    } catch (_) {
      return new Set();
    }
  }

  function persistWalletCreditMotionSeenKeys(uid, keys) {
    const key = walletCreditMotionSeenStorageKey(uid);
    if (!key) return;
    try {
      const list = Array.from(keys || [])
        .map((entry) => String(entry || "").trim())
        .filter(Boolean)
        .slice(-WALLET_CREDIT_MOTION_MAX_SEEN);
      localStorage.setItem(key, JSON.stringify(list));
    } catch (_) {}
  }

  function suspendWalletCreditMotionWatcher(ms = 12000) {
    const duration = Math.max(0, Number(ms) || 0);
    walletCreditMotionWatcherState.suspendUntilMs = Date.now() + duration;
  }

  function handleWalletCreditMotionSnapshot(snapshot) {
    const data = snapshot && typeof snapshot.data === "function" ? (snapshot.data() || {}) : {};
    const entries = collectWalletMotionEntries(data);
    const nextKeys = new Set(entries.map((entry) => String(entry.__entryKey || "").trim()).filter(Boolean));

    const freshEntries = entries.filter((entry) => {
      const key = String(entry.__entryKey || "").trim();
      return key && !walletCreditMotionWatcherState.seenKeys.has(key);
    });
    const now = Date.now();
    const isInitial = walletCreditMotionWatcherState.primed !== true;
    const eligibleEntries = isInitial
      ? freshEntries.filter((entry) => {
          const ts = parseWalletMotionTimestamp(entry);
          return !!ts && Math.abs(now - ts) <= WALLET_CREDIT_MOTION_INITIAL_FRESH_MS;
        })
      : freshEntries;

    walletCreditMotionWatcherState.primed = true;
    walletCreditMotionWatcherState.seenKeys = nextKeys;
    persistWalletCreditMotionSeenKeys(walletCreditMotionWatcherState.uid, nextKeys);

    if (Date.now() < Number(walletCreditMotionWatcherState.suspendUntilMs || 0)) {
      return;
    }

    const latestPayload = eligibleEntries
      .map(classifyWalletMotionEntry)
      .filter(Boolean)
      .pop();
    if (!latestPayload) return;

    showWalletActivityOverlay(latestPayload);
  }

  async function fetchWalletCreditMotionSnapshotFromServer(user, uid) {
    const safeUid = String(uid || "").trim();
    if (!user || !safeUid || typeof user.getIdToken !== "function") return null;
    const info = typeof readSessionInfo === "function" ? (readSessionInfo() || {}) : {};
    const sessionKey = String(info.sessionKey || (typeof getLocalSessionKey === "function" ? getLocalSessionKey() : "") || "").trim();
    if (!sessionKey) return null;
    let requestUrl;
    try {
      const workerBase = window.__getSiteWorkerBaseDefault
        ? String(window.__getSiteWorkerBaseDefault({ trailingSlash: true }) || "").trim()
        : "";
      requestUrl = workerBase ? new URL(workerBase) : new URL("/", window.location.href);
    } catch (_) {
      requestUrl = new URL("/", window.location.href);
    }
    requestUrl.searchParams.set("mode", "client-wallet");
    requestUrl.searchParams.set("useruid", safeUid);
    requestUrl.searchParams.set("sessionKey", sessionKey);
    requestUrl.searchParams.set("limit", "50");
    requestUrl.searchParams.set("_", String(Date.now()));
    const res = await fetch(requestUrl.toString(), {
      method: "GET",
      cache: "no-store"
    });
    const payload = await res.json().catch(() => ({}));
    if (!res.ok || !payload || payload.ok === false) return null;
    const entriesMap = {};
    const wallet = payload && payload.wallet && typeof payload.wallet === "object" ? payload.wallet : {};
    const list = Array.isArray(wallet.items)
      ? wallet.items
      : (Array.isArray(payload.transactions) ? payload.transactions : (Array.isArray(payload.items) ? payload.items : []));
    list.forEach((entry, index) => {
      const key = String(entry && (entry.entryKey || entry.cacheKey || entry.code) || "").trim() || `tx_${index + 1}`;
      entriesMap[key] = entry;
    });
    return { entriesMap };
  }

  function syncWalletCreditMotionWatcher(user) {
    const uid = user && user.uid ? String(user.uid).trim() : "";
    if (!uid) {
      resetWalletCreditMotionWatcher();
      return;
    }
    if (isWalletCreditMotionBlocked(user)) {
      resetWalletCreditMotionWatcher();
      return;
    }
    if (walletCreditMotionWatcherState.uid === uid && walletCreditMotionWatcherState.unsubscribe) return;
    resetWalletCreditMotionWatcher();
    walletCreditMotionWatcherState.uid = uid;
    walletCreditMotionWatcherState.seenKeys = readWalletCreditMotionSeenKeys(uid);
    walletCreditMotionWatcherState.unsubscribe = function(){};
    fetchWalletCreditMotionSnapshotFromServer(user, uid).then((data) => {
      if (!data) return;
      handleWalletCreditMotionSnapshot({
        data: function(){
          return data || {};
        }
      });
    }).catch((err) => {
      try { console.warn("wallet_credit_motion_fetch_failed", err && err.message ? err.message : err); } catch (_) {}
    });
  }

  function initWalletCreditMotionWatcher() {
    if (walletCreditMotionWatcherState.attached) return;
    walletCreditMotionWatcherState.attached = true;
    const syncCurrentWalletWatcherUser = () => {
      try {
        const currentUser = auth && auth.currentUser ? auth.currentUser : null;
        syncWalletCreditMotionWatcher(currentUser || null);
      } catch (_) {
        resetWalletCreditMotionWatcher();
      }
    };
    if (!auth || typeof auth.onAuthStateChanged !== "function") return;
    auth.onAuthStateChanged((user) => {
      syncWalletCreditMotionWatcher(user || null);
    });
    try { window.addEventListener("sessionkey:updated", syncCurrentWalletWatcherUser); } catch (_) {}
    try { window.addEventListener("hashchange", syncCurrentWalletWatcherUser); } catch (_) {}
  }

