  function appendCatalogCardMedia(card, options) {
    const host = card && typeof card === "object" ? card : null;
    const opts = options && typeof options === "object" ? options : {};
    if (!host) return null;

    const label = String(opts.label || opts.title || "Catalog").trim() || "Catalog";
    const realImageUrl = sanitizeCatalogCardMediaUrl(opts.imageUrl || "");
    const imageReferrerPolicy = String(opts.referrerPolicy || "no-referrer").trim() || "no-referrer";
    const requestedLoading = String(opts.loading || "lazy");
    const requestedFetchPriority = String(opts.fetchPriority || opts.fetchpriority || "low");
    const media = document.createElement("div");
    media.className = "catalog-card-media";
    media.setAttribute("aria-hidden", "true");

    const img = document.createElement("img");
    img.setAttribute("draggable", "false");
    img.setAttribute("alt", String(opts.alt || label || "Catalog card"));
    img.setAttribute("loading", requestedLoading);
    img.setAttribute("fetchpriority", requestedFetchPriority);
    img.setAttribute("referrerpolicy", imageReferrerPolicy);
    img.decoding = String(opts.decoding || "async");
    try { img.referrerPolicy = imageReferrerPolicy; } catch (_) {}

    const ensureEmptyState = () => {
      try { host.classList.add("media-empty"); } catch (_) {}
      try { media.classList.add("is-empty"); } catch (_) {}
    };

    const applyFallback = () => {
      ensureEmptyState();
      img.alt = `${label} - بلا صورة`;
      try { img.removeAttribute("src"); } catch (_) {}
      try { img.removeAttribute("srcset"); } catch (_) {}
      try { img.style.display = "none"; } catch (_) {}
    };

    img.addEventListener("error", function() {
      if (img.dataset.placeholderApplied === "1") return;
      img.dataset.placeholderApplied = "1";
      try { applyFallback(); } catch (_) {}
    });

    if (realImageUrl) {
      try { img.style.display = ""; } catch (_) {}
      try {
        if (typeof window.__registerCatalogCardMediaImage === "function" && window.__registerCatalogCardMediaImage(img, realImageUrl, {
          loading: requestedLoading,
          fetchPriority: requestedFetchPriority
        })) {
          media.appendChild(img);
          host.appendChild(media);
          return img;
        }
      } catch (_) {}
      img.src = realImageUrl;
    } else {
      img.dataset.placeholderApplied = "1";
      applyFallback();
    }

    media.appendChild(img);
    host.appendChild(media);
    return img;
  }
