        function readCachedDefaultThemeMode(){
          try {
            var raw = localStorage.getItem('site:theme:v1');
            if (!raw) return '';
            var parsed = JSON.parse(raw) || {};
            var mode = String(
              parsed.defaultMode ||
              parsed.default_mode ||
              parsed.defaultThemeMode ||
              parsed.default_theme_mode ||
              ''
            ).trim().toLowerCase();
            return mode === 'dark' || mode === 'light' ? mode : '';
          } catch(_){}
          return '';
        }

