      function parseApiAccessCacheValue(value){
        if (value == null) return null;
        if (typeof value === 'boolean') return value;
        if (typeof value === 'number') return value !== 0;
        var raw = String(value || '').trim().toLowerCase();
        if (!raw) return null;
        if (['1', 'true', 'on', 'yes', 'enabled', 'active'].indexOf(raw) >= 0) return true;
        if (['0', 'false', 'off', 'no', 'disabled', 'inactive'].indexOf(raw) >= 0) return false;
        return null;
      }

      function resolveApiRouteUid(){
        try {
          if (typeof firebase !== 'undefined' && firebase && typeof firebase.auth === 'function') {
            var authInst = firebase.auth();
            if (authInst && authInst.currentUser && authInst.currentUser.uid) {
              return String(authInst.currentUser.uid || '').trim();
            }
          }
        } catch (_) {}
        try {
          var rawInfo = localStorage.getItem('sessionKeyInfo');
          if (rawInfo) {
            var parsedInfo = JSON.parse(rawInfo);
            if (parsedInfo && parsedInfo.uid) return String(parsedInfo.uid || '').trim();
          }
        } catch (_) {}
        try {
          var uid = String(localStorage.getItem('auth:lastUid') || localStorage.getItem('session:lastUid') || '').trim();
          if (uid) return uid;
        } catch (_) {}
        return '';
      }

      function readApiRouteAccessCache(){
        var uid = resolveApiRouteUid();
        if (!uid) return null;
        try {
          var raw = localStorage.getItem('api:access:enabled:' + uid);
          return parseApiAccessCacheValue(raw);
        } catch (_) {
          return null;
        }
      }

      function ensureApiRouteAllowedFromCache(){
        var cached = readApiRouteAccessCache();
        if (cached !== false) return true;
        try { alert('واجهة API غير مفعلة لهذا الحساب من الإدارة.'); } catch (_){}
        try {
          if (typeof navigateHome === 'function') navigateHome();
          else location.hash = '#/';
        } catch (_) {
          try { location.hash = '#/'; } catch (__){}
        }
        return false;
      }

      function releaseInlineWalletBootLoader(){
        try {
          if (inlineWalletBootLoaderTimer) {
            clearTimeout(inlineWalletBootLoaderTimer);
            inlineWalletBootLoaderTimer = null;
          }
        } catch(_){}
        try {
          var countriesLoading = false;
          try {
            countriesLoading =
              window.__DEPOSIT_INLINE_COUNTRIES_LOADING__ === true ||
              (document.documentElement && document.documentElement.classList.contains('deposit-countries-loader-pending')) ||
              (document.body && document.body.classList.contains('deposit-countries-loader-pending'));
          } catch(_){ countriesLoading = false; }
          if (countriesLoading) {
            window.__INLINE_WALLET_BOOT_HOLD__ = true;
            try {
              if (typeof window.__setInlineWalletRoutePending === 'function') window.__setInlineWalletRoutePending(true);
            } catch(_){}
            return;
          }
          var hadBootHold = !!window.__INLINE_WALLET_BOOT_HOLD__;
          window.__INLINE_WALLET_BOOT_HOLD__ = false;
          try {
            if (typeof window.__setInlineWalletRoutePending === 'function') window.__setInlineWalletRoutePending(false);
          } catch(_){}
          if (!hadBootHold) return;
          if (typeof window.__releasePageLoader === 'function') {
            window.__releasePageLoader();
          } else if (typeof hidePageLoader === 'function') {
            hidePageLoader();
          }
        } catch(_){}
      }

      function holdInlineWalletBootLoader(routeKey){
        try {
          var keyFromRoute = String(routeKey || '').toLowerCase();
          var keyFromHash = String((location.hash || '').replace(/^#\/?/, '').split('/')[0] || '').toLowerCase();
          var targetKey = keyFromRoute || keyFromHash;
          if (!isWalletFlowRouteKey(targetKey)) return;
          var alreadyHeld = !!window.__INLINE_WALLET_BOOT_HOLD__;
          window.__INLINE_WALLET_BOOT_HOLD__ = true;
          try {
            if (typeof window.__setInlineWalletRoutePending === 'function') window.__setInlineWalletRoutePending(true);
          } catch(_){}
          if (!alreadyHeld) {
            if (typeof window.__holdPageLoader === 'function') {
              window.__holdPageLoader();
            } else if (typeof showPageLoader === 'function') {
              showPageLoader({ hold: true });
            }
          } else {
            try { window.__LOADER_HOLD_ACTIVE__ = true; } catch(_){}
            try {
              if (typeof showPageLoader === 'function') showPageLoader({ hold: true, replay: true });
            } catch(_){}
          }
          if (inlineWalletBootLoaderTimer) {
            clearTimeout(inlineWalletBootLoaderTimer);
            inlineWalletBootLoaderTimer = null;
          }
        } catch(_){}
      }
      try { window.__releaseInlineWalletBootLoader = releaseInlineWalletBootLoader; } catch(_){}

