function recomputeAndRender(){
  const uid = getOrdersCurrentUser()?.uid;
  if (!uid) return;
  SUPPRESS_ORDER_ANIM = true;
  try {
    renderOrders(cacheToSortedArray(uid));
  } finally {
    SUPPRESS_ORDER_ANIM = false;
  }
}

